                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                </div>
                <span className="text-[9px] md:text-[10px] font-mono text-green-400 tracking-widest uppercase font-semibold">
                  Market Open
                </span>
              </div>
            </FadeIn>

            <FadeIn isActive={activeSection === 'personality'} delay={100}>
              <h1 className="text-4xl sm:text-6xl md:text-8xl font-black tracking-tighter mb-2 select-none leading-none brand-hover">
                danya<span className="text-brand drop-shadow-glow">.shou</span>
              </h1>
            </FadeIn>

            <FadeIn isActive={activeSection === 'personality'} delay={300}>
              <p className="text-brand/60 font-mono text-[10px] md:text-base tracking-[0.3em] md:tracking-[0.5em] uppercase mb-6">
                shou.trade architecture
              </p>
            </FadeIn>

            <FadeIn isActive={activeSection === 'personality'} delay={500}>
              <div className="h-px w-16 md:w-24 bg-neutral-800 my-4 md:my-6 mx-auto" />
            </FadeIn>

            <FadeIn isActive={activeSection === 'personality'} delay={700}>
              <p className="text-lg md:text-2xl font-light text-neutral-300 tracking-wide max-w-xs md:max-w-none">
                Профессиональный <span className="font-medium text-white italic">Трейдинг</span>
              </p>
            </FadeIn>

            <FadeIn isActive={activeSection === 'personality'} delay={900}>
              <p className="mt-4 text-dark-muted text-xs md:text-sm max-w-[280px] md:max-w-md mx-auto leading-relaxed">
                Дисциплина, терпение, риск менеджмент, самоконтроль, дистанция
              </p>
            </FadeIn>
          </div>

          <FadeIn isActive={activeSection === 'personality'} delay={1200} className="absolute bottom-8 md:bottom-10">
            <button 
              onClick={() => handleNavigation('experience')}
              className="animate-bounce text-dark-muted hover:text-brand transition-colors p-2"
            >
              <ChevronDown size={28} />
            </button>
          </FadeIn>
        </Section>

        <Section id="experience">
          <div className="w-full max-w-6xl mx-auto z-10 flex flex-col md:grid md:grid-cols-2 gap-8 md:gap-12 items-center">
            <div className="w-full">
              <FadeIn isActive={activeSection === 'experience'} delay={100}>
                <h2 className="text-2xl md:text-5xl font-bold mb-6 flex items-center gap-3">
                  <span className="w-1 h-6 md:w-1.5 md:h-10 bg-brand rounded-full shadow-[0_0_15px_rgba(34,211,238,0.8)]"></span>
                  Опыт
                </h2>
              </FadeIn>

              <div className="grid grid-cols-1 gap-3 md:gap-4 mb-2">
                {TRADING_STATS.map((stat, idx) => (
                  <FadeIn key={idx} isActive={activeSection === 'experience'} delay={200 + (idx * 100)}>
                    <div className="bg-dark-card/60 backdrop-blur-md border border-neutral-800/50 p-4 rounded-2xl hover:border-brand/30 transition-all group">
                      <h3 className="text-dark-muted text-[10px] md:text-xs uppercase tracking-wider mb-1 group-hover:text-brand transition-colors">{stat.label}</h3>
                      <p className="text-lg md:text-2xl font-bold text-white mb-0.5">{stat.value}</p>
                      <p className="text-[10px] md:text-sm text-neutral-500 leading-tight">{stat.description}</p>
                    </div>
                  </FadeIn>
                ))}
              </div>
            </div>

            <FadeIn isActive={activeSection === 'experience'} delay={500} className="w-full h-full max-h-[320px] md:max-h-none">
