                  </h3>
                  <div className="flex-1 w-full min-h-0">
                     <ResponsiveContainer width="100%" height="100%">
                      <RadarChart cx="50%" cy="50%" outerRadius="65%" data={SKILL_DATA}>
                        <PolarGrid stroke="#262626" />
                        <PolarAngleAxis 
                          dataKey="subject" 
                          tick={{ fill: '#737373', fontSize: 9, fontWeight: 500 }}
                        />
                        <PolarRadiusAxis angle={30} domain={[0, 10]} tick={false} axisLine={false} />
                        <RechartsRadar
                          name="Skills"
                          dataKey="A"
                          stroke="#22d3ee"
                          strokeWidth={2}
                          fill="#22d3ee"
                          fillOpacity={0.2}
                        />
                      </RadarChart>
                    </ResponsiveContainer>
                  </div>
              </div>
            </FadeIn>
          </div>
        </Section>

        <Section id="ai-chat">
          <div className="w-full max-w-4xl z-10 flex flex-col items-center">
            <FadeIn isActive={activeSection === 'ai-chat'} delay={100}>
              <div className="text-center mb-6">
                <h2 className="text-2xl md:text-5xl font-bold mb-2 flex items-center justify-center gap-2 md:gap-3">
                  <Sparkles className="text-brand" size={24} />
                  Ask <span className="text-brand drop-shadow-glow">Shou AI</span>
