                <p className="text-dark-muted text-[10px] md:text-base max-w-xs mx-auto px-4 leading-relaxed">
                  Анализ рыночных настроений или вопросы о трейдинге.
                </p>
              </div>
            </FadeIn>

            <FadeIn isActive={activeSection === 'ai-chat'} delay={300} className="w-full px-2 md:px-4">
              <AiChat />
            </FadeIn>
          </div>
        </Section>

        <Section id="connect">
          <div className="w-full max-w-4xl z-10 text-center px-4">
            <FadeIn isActive={activeSection === 'connect'} delay={100}>
              <h2 className="text-3xl md:text-6xl font-bold mb-3">
                Контакты
              </h2>
            </FadeIn>

            <FadeIn isActive={activeSection === 'connect'} delay={200}>
              <p className="text-dark-muted mb-8 md:mb-12 text-sm md:text-lg">
                Присоединяйся к сети. Следи за путем danya.shou.
              </p>
            </FadeIn>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-3 md:gap-4 text-left">
              {SOCIAL_LINKS.map((link, idx) => (
                <FadeIn key={link.name} isActive={activeSection === 'connect'} delay={300 + (idx * 100)}>
                  <SocialCard link={link} />
                </FadeIn>
              ))}
            </div>

            <FadeIn isActive={activeSection === 'connect'} delay={800}>
              <footer className="mt-12 md:mt-20 text-neutral-600 text-[10px] md:text-sm font-mono uppercase tracking-widest pb-8">
                © {new Date().getFullYear()} danya.shou
              </footer>
            </FadeIn>
          </div>
        </Section>
      </main>

      {/* === PROJECTS VIEW === */}
      {viewMode === 'projects' && (
        <div className="absolute inset-0 z-[60] pt-24 px-4 md:px-8 pb-12 overflow-y-auto bg-dark-bg animate-fade-in-up no-scrollbar">
          <div className="fixed inset-0 z-0 pointer-events-none">
            <div className="absolute inset-0 bg-[#050505]" />
            <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-brand/5 blur-[120px] rounded-full" />
            <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-brand/5 blur-[100px] rounded-full" />
            <div className="absolute inset-0 opacity-[0.03]" style={{ backgroundImage: `linear-gradient(#22d3ee 1px, transparent 1px), linear-gradient(90deg, #22d3ee 1px, transparent 1px)`, backgroundSize: '30px 30px' }} />
          </div>

          <div className="w-full max-w-7xl mx-auto h-full flex flex-col relative z-10">
            <div className="flex flex-col items-center mb-10 md:mb-16 relative">
               <button 
                 onClick={() => setViewMode('main')}
                 className="md:absolute md:left-0 top-0 flex items-center text-neutral-400 hover:text-white transition-colors text-xs md:text-sm group mb-6 md:mb-0 pointer-events-auto"
               >
                 <ArrowLeft className="mr-2 transition-transform group-hover:-translate-x-1" size={16} />
                 Вернуться назад
               </button>

               <div className="text-center">
                  <p className="text-brand/50 font-mono text-[9px] md:text-[10px] tracking-[0.4em] uppercase mb-1">Portfolio Selection</p>
                  <h2 className="text-3xl md:text-6xl font-black tracking-tighter mb-4 text-white leading-none">
                    ПРОЕКТЫ
                  </h2>
                  <div className="h-1 w-12 bg-brand mx-auto rounded-full shadow-[0_0_20px_rgba(34,211,238,0.4)]" />
               </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8 pb-20">
              {PROJECTS_DATA.map((project) => (
                <ProjectCard key={project.id} project={project} />
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
